import React, { useState, useEffect } from "react";
import Logo from "./Logo";
import LoginForm from "./LoginForm";
import RegisterForm from "./RegisterForm";
import HomePage from "./HomePage"; // nếu sau này muốn thêm trang chủ

export default function App() {
  const [screen, setScreen] = useState("logo"); // logo | login | register | home

  // Tự động chuyển logo → login sau 2 giây
  useEffect(() => {
    if (screen === "logo") {
      const timer = setTimeout(() => setScreen("login"), 2000);
      return () => clearTimeout(timer);
    }
  }, [screen]);

  // Hàm handle login thành công
  const handleLoginSuccess = () => {
    setScreen("home"); // chuyển sang HomePage
  };

  return (
    <div>
      {screen === "logo" && <Logo />}

      {screen === "login" && (
        <LoginForm
          goToRegister={() => setScreen("register")}
          onLoginSuccess={handleLoginSuccess} // truyền hàm login thành công
        />
      )}

      {screen === "register" && (
        <RegisterForm
          goToLogin={() => setScreen("login")}
        />
      )}

      {screen === "home" && <HomePage />}
    </div>
  );
}
